   285	    use naga::back::hlsl;
   286	
   287	    println!("generating HLSL");
   288	
   289	    let (module, info) =
   290	        naga::back::pipeline_constants::process_overrides(module, info, None, pipeline_constants)
   291	            .expect("override evaluation failed");
   292	
   293	    let mut options = options.clone();
   294	    options.mesh_shader_primitive_indices_clamp = shared_info.mesh_output_validation;
   295	    options.task_dispatch_limits = shared_info.task_limits;
   296	
   297	    let mut buffer = String::new();
   298	    let pipeline_options = Default::default();
   299	    let mut writer = hlsl::Writer::new(&mut buffer, &options, &pipeline_options);
   300	    let reflection_info = writer
   301	        .write(&module, &info, frag_ep.as_ref())
   302	        .expect("HLSL write failed");
   303	
   304	    input.write_output_file("hlsl", "hlsl", buffer, DIR_OUT);
