   310	    for (index, ep) in module.entry_points.iter().enumerate() {
   311	        let name = match reflection_info.entry_point_names[index] {
   312	            Ok(ref name) => name,
   313	            Err(_) => continue,
   314	        };
   315	        match ep.stage {
   316	            naga::ShaderStage::Vertex => &mut config.vertex,
   317	            naga::ShaderStage::Fragment => &mut config.fragment,
   318	            naga::ShaderStage::Compute => &mut config.compute,
   319	            naga::ShaderStage::Task => &mut config.task,
   320	            naga::ShaderStage::Mesh => &mut config.mesh,
   321	            naga::ShaderStage::RayGeneration
   322	            | naga::ShaderStage::AnyHit
   323	            | naga::ShaderStage::ClosestHit
   324	            | naga::ShaderStage::Miss => unreachable!(),
   325	        }
   326	        .push(hlsl_snapshots::ConfigItem {
